import{_ as a,c as o,a0 as i,o as l}from"./chunks/framework.B6JXc2q-.js";const s=JSON.parse('{"title":"自动 runtime reload 验收基线","description":"","frontmatter":{},"headers":[],"relativePath":"spec/auth_auto_runtime_reload_acceptance.md","filePath":"spec/auth_auto_runtime_reload_acceptance.md"}'),r={name:"spec/auth_auto_runtime_reload_acceptance.md"};function t(d,e,c,u,h,n){return l(),o("div",null,e[0]||(e[0]=[i('<h1 id="自动-runtime-reload-验收基线" tabindex="-1">自动 runtime reload 验收基线 <a class="header-anchor" href="#自动-runtime-reload-验收基线" aria-label="Permalink to &quot;自动 runtime reload 验收基线&quot;">​</a></h1><p>版本：v1.0 状态：收口文档 最后更新：2026-04-03 适用范围：<code>xiaomusic/auth.py</code>、<code>xiaomusic/api/routers/system.py</code> 的自动恢复登录闭环验收</p><hr><h2 id="_1-目的" tabindex="-1">1. 目的 <a class="header-anchor" href="#_1-目的" aria-label="Permalink to &quot;1. 目的&quot;">​</a></h2><p>本文档固化当前自动恢复登录主线的验收口径：</p><ul><li>扫码登录成功后，系统能否自动把 runtime 拉回 healthy</li><li><code>degraded + persistent_auth_available=true + short_session_available=true</code> 时，系统能否自动触发 runtime reload</li><li><code>verify_auth_failure_detected=true</code> 时，runtime reload 是否正确 handoff 到既有 short-session 恢复链</li><li>网络/连接错误时，是否只进入 cooldown/backoff，而不误入 auth handoff</li></ul><p>本文档只做收口，不定义新逻辑。</p><hr><h2 id="_2-当前行为基线" tabindex="-1">2. 当前行为基线 <a class="header-anchor" href="#_2-当前行为基线" aria-label="Permalink to &quot;2. 当前行为基线&quot;">​</a></h2><h3 id="_2-1-登录待恢复" tabindex="-1">2.1 登录待恢复 <a class="header-anchor" href="#_2-1-登录待恢复" aria-label="Permalink to &quot;2.1 登录待恢复&quot;">​</a></h3><p>后端语义：</p><ul><li><code>auth_mode=degraded</code></li><li><code>persistent_auth_available=true</code></li><li><code>short_session_available=true</code></li><li>runtime 尚未 ready</li></ul><p>这时系统会自动尝试一次 runtime reload，不再只依赖人工点击按钮。</p><h3 id="_2-2-自动-runtime-reload-的触发入口" tabindex="-1">2.2 自动 runtime reload 的触发入口 <a class="header-anchor" href="#_2-2-自动-runtime-reload-的触发入口" aria-label="Permalink to &quot;2.2 自动 runtime reload 的触发入口&quot;">​</a></h3><ul><li><code>init_all_data()</code></li><li><code>keepalive_loop()</code></li></ul><h3 id="_2-3-自动-runtime-reload-的触发条件" tabindex="-1">2.3 自动 runtime reload 的触发条件 <a class="header-anchor" href="#_2-3-自动-runtime-reload-的触发条件" aria-label="Permalink to &quot;2.3 自动 runtime reload 的触发条件&quot;">​</a></h3><ul><li><code>auth_mode=degraded</code></li><li><code>persistent_auth_available=true</code></li><li><code>short_session_available=true</code></li><li>当前没有进行中的同类恢复</li><li>不在 cooldown / backoff 窗口内</li></ul><h3 id="_2-4-结果分流" tabindex="-1">2.4 结果分流 <a class="header-anchor" href="#_2-4-结果分流" aria-label="Permalink to &quot;2.4 结果分流&quot;">​</a></h3><ul><li><code>runtime_auth_ready=true</code>：进入 <code>healthy</code></li><li><code>verify_auth_failure_detected=true</code>：short session 已被证伪，handoff 到既有 short-session 恢复链</li><li>网络/连接失败：保留 <code>degraded</code>，进入 cooldown / backoff，不误判为 auth failure</li></ul><h3 id="_2-5-手动-refresh-语义" tabindex="-1">2.5 手动 refresh 语义 <a class="header-anchor" href="#_2-5-手动-refresh-语义" aria-label="Permalink to &quot;2.5 手动 refresh 语义&quot;">​</a></h3><ul><li><code>POST /api/auth/refresh</code></li><li><code>POST /api/auth/refresh_runtime</code></li></ul><p>手动入口语义保持不变，和自动触发共享同一 runtime reload 核心链路。</p><hr><h2 id="_3-真实服务器验收-checklist" tabindex="-1">3. 真实服务器验收 checklist <a class="header-anchor" href="#_3-真实服务器验收-checklist" aria-label="Permalink to &quot;3. 真实服务器验收 checklist&quot;">​</a></h2><h3 id="_3-1-扫码登录后自动触发" tabindex="-1">3.1 扫码登录后自动触发 <a class="header-anchor" href="#_3-1-扫码登录后自动触发" aria-label="Permalink to &quot;3.1 扫码登录后自动触发&quot;">​</a></h3><ul><li>[ ] 扫码登录成功后，<code>/api/v1/debug/auth_state</code> 显示 <code>persistent_auth_available=true</code> 且 <code>short_session_available=true</code></li><li>[ ] 未手动点击刷新时，<code>/api/v1/debug/auth_runtime_reload_state</code> 出现 <code>auto_runtime_reload_triggered=true</code></li><li>[ ] 自动触发来源可见为 <code>init_all_data</code> 或 <code>keepalive</code></li><li>[ ] 最终状态回到 <code>healthy</code></li></ul><h3 id="_3-2-degraded-自动触发-runtime-reload" tabindex="-1">3.2 degraded 自动触发 runtime reload <a class="header-anchor" href="#_3-2-degraded-自动触发-runtime-reload" aria-label="Permalink to &quot;3.2 degraded 自动触发 runtime reload&quot;">​</a></h3><ul><li>[ ] 服务器处于 <code>auth_mode=degraded</code></li><li>[ ] <code>persistent_auth_available=true</code></li><li>[ ] <code>short_session_available=true</code></li><li>[ ] 没有同类恢复进行中、没有 cooldown/backoff 时，会自动排队一次 runtime reload</li><li>[ ] <code>auto_runtime_reload_result</code> 有明确结果</li></ul><h3 id="_3-3-verify-auth-failure-handoff" tabindex="-1">3.3 verify auth failure handoff <a class="header-anchor" href="#_3-3-verify-auth-failure-handoff" aria-label="Permalink to &quot;3.3 verify auth failure handoff&quot;">​</a></h3><ul><li>[ ] <code>verify_auth_failure_detected=true</code></li><li>[ ] <code>short_session_invalidated_after_verify=true</code></li><li>[ ] <code>recovery_chain_handoff=true</code></li><li>[ ] <code>recovery_chain_result</code> 明确落点可见</li></ul><h3 id="_3-4-网络失败不误触发-auth-handoff" tabindex="-1">3.4 网络失败不误触发 auth handoff <a class="header-anchor" href="#_3-4-网络失败不误触发-auth-handoff" aria-label="Permalink to &quot;3.4 网络失败不误触发 auth handoff&quot;">​</a></h3><ul><li>[ ] <code>verify_error_text</code> 是网络/连接错误时，不出现 <code>verify_auth_failure_detected=true</code></li><li>[ ] 不出现 <code>recovery_chain_handoff=true</code></li><li>[ ] 自动触发结果进入 cooldown/backoff</li></ul><h3 id="_3-5-长稳验收" tabindex="-1">3.5 长稳验收 <a class="header-anchor" href="#_3-5-长稳验收" aria-label="Permalink to &quot;3.5 长稳验收&quot;">​</a></h3><ul><li>[ ] 观察到从 <code>degraded</code> 自动回到 <code>healthy</code> 的真实样本</li><li>[ ] 24h 左右掉线后，尽可能无需人工点击“刷新运行时”即可恢复</li><li>[ ] 只有长期态缺失或硬故障时才需要人工重新登录</li></ul><hr><h2 id="_4-记录要求" tabindex="-1">4. 记录要求 <a class="header-anchor" href="#_4-记录要求" aria-label="Permalink to &quot;4. 记录要求&quot;">​</a></h2><p>每次服务器验收至少保留：</p><ul><li>刷新前 <code>auth_state</code></li><li>刷新前 <code>auth_runtime_reload_state</code></li><li>刷新后 <code>auth_state</code></li><li>刷新后 <code>auth_runtime_reload_state</code></li><li>关键日志里 <code>auto_runtime_reload_*</code>、<code>verify_auth_failure_detected</code>、<code>recovery_chain_handoff</code> 相关字段</li></ul>',38)]))}const f=a(r,[["render",t]]);export{s as __pageData,f as default};
